import argparse
import json
from pathlib import Path
from typing import List

from transformers import AutoTokenizer
from vllm import LLM, SamplingParams

SYSTEM_INSTRUCTION = (
    "You are given a disfluent sentence generated by an Automatic Speech Recognition (ASR) system.\n"
    "This sentence may contain disfluencies, including but not limited to repetitions, fillers, "
    "discourse markers, and false starts in Marathi.\n"
    "Your task is to remove these disfluencies while preserving the grammatical structure and meaning.\n"
    "Return only the corrected, well-formed fluent Marathi sentence. Do not add explanations, labels, or quotes."
)

USER_TEMPLATE = """Language: Marathi
Disfluent ASR sentence:
{disfluent}
"""

def read_lines(p: str) -> List[str]:
    with open(p, "r", encoding="utf-8") as f:
        return [line.rstrip("\n\r") for line in f]

def build_chat_prompt(tokenizer, disfluent: str) -> str:
    messages = [
        {"role": "system", "content": SYSTEM_INSTRUCTION},
        {"role": "user", "content": USER_TEMPLATE.format(disfluent=disfluent.replace("```", "``` "))},
    ]
    return tokenizer.apply_chat_template(messages, tokenize=False, add_generation_prompt=True)

def main():
    ap = argparse.ArgumentParser(description="Zero-shot disfluency correction (Marathi only) with Qwen Instruct via vLLM.")
    ap.add_argument("--model", default="Qwen/Qwen2.5-3B-Instruct",
                    help="HF model id or local path (chat/instruct model recommended).")
    ap.add_argument("--disfluent", required=True, help="Text file with one disfluent Marathi sentence per line.")
    ap.add_argument("--out_jsonl", default="marathi_corrected.jsonl", help="Output JSONL with {disfluent, corrected}.")
    ap.add_argument("--out_txt", default="marathi_corrected.txt", help="Output TXT with one corrected line.")
    ap.add_argument("--tp", type=int, default=1, help="vLLM tensor_parallel_size")
    ap.add_argument("--dtype", default="bfloat16", choices=["bfloat16", "float16", "float32"])
    ap.add_argument("--gpu_util", type=float, default=0.55, help="vLLM gpu_memory_utilization (0.1–0.95).")
    ap.add_argument("--max_model_len", type=int, default=2048, help="Reduce if GPU memory is tight.")
    ap.add_argument("--max_tokens", type=int, default=128)
    ap.add_argument("--temperature", type=float, default=0.0)
    ap.add_argument("--top_p", type=float, default=1.0)
    ap.add_argument("--seed", type=int, default=7)
    args = ap.parse_args()

    # Load input
    dis = read_lines(args.disfluent)
    if not dis:
        raise SystemExit("[error] Empty disfluent file.")

    # Tokenizer & model
    tokenizer = AutoTokenizer.from_pretrained(args.model, trust_remote_code=False)
    llm = LLM(
        model=args.model,
        tensor_parallel_size=args.tp,
        dtype=args.dtype,
        trust_remote_code=False,
        gpu_memory_utilization=args.gpu_util,
        max_model_len=args.max_model_len,
    )

    # Build prompts
    prompts = [build_chat_prompt(tokenizer, d) for d in dis]

    # Sampling
    stops = []
    if tokenizer.eos_token:
        stops.append(tokenizer.eos_token)

    sampling = SamplingParams(
        temperature=args.temperature,
        top_p=args.top_p,
        max_tokens=args.max_tokens,
        stop=stops,
        seed=args.seed,
    )

    # Generate
    outputs = llm.generate(prompts, sampling)
    generations = [o.outputs[0].text if o.outputs else "" for o in outputs]

    # Clean
    def clean(t: str) -> str:
        s = (t or "").strip()
        if len(s) >= 2 and ((s[0] == s[-1] == '"') or (s[0] == s[-1] in ["“", "’"])):
            s = s[1:-1].strip()
        for prefix in ["Corrected:", "Output:", "Fluent:", "Correction:"]:
            if s.lower().startswith(prefix.lower()):
                s = s[len(prefix):].strip()
        return s

    corrected = [clean(g) for g in generations]

    # Write outputs
    out_jsonl = Path(args.out_jsonl)
    out_txt = Path(args.out_txt)
    out_jsonl.parent.mkdir(parents=True, exist_ok=True)
    out_txt.parent.mkdir(parents=True, exist_ok=True)

    with open(out_jsonl, "w", encoding="utf-8") as f:
        for d, c in zip(dis, corrected):
            obj = {"disfluent": d, "corrected": c}
            f.write(json.dumps(obj, ensure_ascii=False) + "\n")

    with open(out_txt, "w", encoding="utf-8") as f:
        for c in corrected:
            f.write(c + "\n")

    print(f"✅ Wrote: {out_jsonl} and {out_txt}")

if __name__ == "__main__":
    main()
